export const WRITE_PERMISSION_BITS = WRITE_PERMISSION_KEYS.map(
	permissionKey => PERMISSION_BIT_BY_KEY[permissionKey]
);

export const ALL_PERMISSION_BITS = Object.values(PERMISSION_BIT_BY_KEY);

export function normalizePermissionKey(value: unknown): AdminPermissionKey | null {
	const normalized = String(value || '').trim();
	return normalized in PERMISSION_BIT_BY_KEY
		? (normalized as AdminPermissionKey)
		: null;
}

export function parsePermissionMask(mask: unknown) {
	if (typeof mask === 'bigint') {
		return mask;
	}
	if (typeof mask === 'number' && Number.isFinite(mask)) {
		return BigInt(Math.trunc(mask));
	}
	if (typeof mask === 'string' && mask.trim()) {
		try {
			return BigInt(mask.trim());
		} catch (error) {
			return ZERO_PERMISSION_MASK;
		}
	}
	return ZERO_PERMISSION_MASK;
}

export function formatPermissionMask(mask: bigint) {
	return mask.toString();
}

export function resolvePermissionMask(
	perms: readonly string[] = [],
	options?: { isAdmin?: boolean }
) {
	let mask = ZERO_PERMISSION_MASK;
	if (options?.isAdmin) {
		mask |= SUPER_ADMIN_PERMISSION_BIT;
	}
	for (const permissionKey of perms) {
		const normalizedPermissionKey = normalizePermissionKey(permissionKey);
		if (normalizedPermissionKey) {
			mask |= PERMISSION_BIT_BY_KEY[normalizedPermissionKey];
		}
	}
	return formatPermissionMask(mask);
}

export function hasPermissionBit(mask: unknown, required: unknown) {
	const parsedMask = parsePermissionMask(mask);
	const parsedRequired = parsePermissionMask(required);
	if (parsedRequired === ZERO_PERMISSION_MASK) {
		return true;
	}
	return (
		(parsedMask & SUPER_ADMIN_PERMISSION_BIT) === SUPER_ADMIN_PERMISSION_BIT ||
		(parsedMask & parsedRequired) === parsedRequired
	);
}

export function hasAnyPermissionBit(mask: unknown, requiredBits: Iterable<unknown>) {
	const parsedMask = parsePermissionMask(mask);
	if ((parsedMask & SUPER_ADMIN_PERMISSION_BIT) === SUPER_ADMIN_PERMISSION_BIT) {
		return true;
	}
	for (const requiredBit of requiredBits) {
		const parsedRequired = parsePermissionMask(requiredBit);
		if (
			parsedRequired !== ZERO_PERMISSION_MASK &&
			(parsedMask & parsedRequired) === parsedRequired
		) {
			return true;
		}
	}
	return false;
}

